framework_css:
/*
  Design system for municipal nursery and daycare framework
  Visual style: warm, playful, slightly retro, with rounded shapes and soft creams/yellows.
*/

:root {
  /* Primary brand colors (from design) */
  --color-primary-amber: #FFC64A;   /* numbered circles, star */
  --color-primary-brown: #5A3A12;   /* main headings, nav text */

  /* Secondary background tones */
  --color-secondary-cream: #FFF4D8; /* page background */
  --color-secondary-sand: #F5D28A;  /* footer and accent panels */

  /* Accent colors */
  --color-accent-orange: #FF9F1C;   /* small accents, highlights */
  --color-accent-lime: #C7D93F;     /* playful green accent */

  /* Neutral / supporting */
  --color-neutral-white: #FFFFFF;
  --color-neutral-cream: #FFF4D8;
  --color-neutral-brown: #8A6C3C;   /* body text */

  /* Semantic (for future form styles) */
  --color-success: #5CB85C;
  --color-error: #D9534F;
  --color-warning: #F0AD4E;
  --color-info: #5BC0DE;

  /* Shadows */
  --shadow-soft: 0 8px 24px rgba(90, 58, 18, 0.12);
  --shadow-subtle: 0 2px 6px rgba(90, 58, 18, 0.08);

  /* Typography */
  --font-heading: 'Baloo 2', Helvetica, Arial, sans-serif;
  --font-body: 'Nunito', 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;

  --fs-body: 16px;
  --fs-small: 13px;
  --fs-h1: 56px; /* hero-level heading size */
  --fs-h2: 34px;
  --fs-h3: 24px;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-2: 4px;
  --space-4: 8px;
  --space-8: 16px;
  --space-12: 24px;
  --space-16: 32px;
  --space-24: 48px;
  --space-32: 64px;

  /* Radii */
  --radius-soft: 10px;
  --radius-pill: 999px;
  --radius-card: 28px; /* large, toy-like rounded corners */

  /* Layout */
  --layout-max-width: 1120px;
}

/* Global reset-ish rules */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body.site-body {
  margin: 0;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  color: var(--color-neutral-brown);
  background-color: var(--color-secondary-cream);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
}

a:focus-visible,
button:focus-visible,
input:focus-visible,
label:focus-visible {
  outline: 3px solid var(--color-accent-lime);
  outline-offset: 2px;
}

/* Visually hidden utility */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Skip link for keyboard users */
.skip-link {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  top: 8px;
  padding: 8px 16px;
  background-color: var(--color-primary-amber);
  color: var(--color-primary-brown);
  border-radius: var(--radius-pill);
  font-weight: 600;
  text-decoration: none;
  box-shadow: var(--shadow-subtle);
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.15s ease-in-out;
  z-index: 1000;
}

.skip-link:focus {
  opacity: 1;
  pointer-events: auto;
}

/* Header */
.site-header {
  position: relative;
  z-index: 50;
  background-color: rgba(255, 244, 216, 0.96);
  backdrop-filter: blur(6px);
  box-shadow: 0 2px 6px rgba(90, 58, 18, 0.06);
}

.site-header__inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-8);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-8);
}

/* Brand / logo area */
.brand {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.brand__icon {
  width: 44px;
  height: 44px;
  border-radius: 16px;
  background: linear-gradient(145deg, var(--color-primary-amber), var(--color-accent-orange));
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-primary-brown);
  font-family: var(--font-heading);
  font-size: 26px;
  box-shadow: var(--shadow-subtle);
}

.brand__text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand__kicker {
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: rgba(90, 58, 18, 0.7);
}

.brand__name {
  font-family: var(--font-heading);
  font-size: 22px;
  color: var(--color-primary-brown);
}

/* Main navigation */
.main-nav {
  display: flex;
}

.main-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

.main-nav__item {
  position: relative;
}

.main-nav__link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 14px;
  border-radius: var(--radius-pill);
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 600;
  color: var(--color-primary-brown);
  text-decoration: none;
  letter-spacing: 0.01em;
  transition: background-color 0.15s ease, box-shadow 0.15s ease, transform 0.1s ease;
}

.main-nav__link:hover {
  background-color: var(--color-secondary-sand);
  box-shadow: var(--shadow-subtle);
  transform: translateY(-1px);
}

.main-nav__link:active {
  transform: translateY(0);
  box-shadow: none;
}

/* Active state hook for pages to use if desired */
.main-nav__link--active {
  background-color: var(--color-primary-amber);
  box-shadow: var(--shadow-subtle);
}

/* Mobile nav toggle */
.nav-toggle {
  display: none;
}

.nav-toggle__label {
  display: none;
  cursor: pointer;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 4px;
  width: 40px;
  height: 40px;
  border-radius: 14px;
  background-color: rgba(245, 210, 138, 0.9);
  box-shadow: var(--shadow-subtle);
}

.nav-toggle__line {
  width: 20px;
  height: 2px;
  border-radius: 999px;
  background-color: var(--color-primary-brown);
}

/* Layout for main content area */
.site-main {
  flex: 1;
  max-width: var(--layout-max-width);
  width: 100%;
  margin: 0 auto;
  padding: var(--space-16) var(--space-8) var(--space-24);
}

/* Footer */
.site-footer {
  margin-top: var(--space-16);
  background-color: var(--color-secondary-sand);
  border-radius: var(--radius-card) var(--radius-card) 0 0;
  box-shadow: 0 -4px 14px rgba(90, 58, 18, 0.12);
  color: var(--color-primary-brown);
}

.site-footer__inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-16) var(--space-8) var(--space-8);
  display: grid;
  grid-template-columns: minmax(0, 2fr) minmax(0, 3fr);
  gap: var(--space-16);
}

.footer-brand__title {
  margin: 0 0 var(--space-4);
  font-family: var(--font-heading);
  font-size: var(--fs-h3);
  line-height: var(--lh-tight);
}

.footer-brand__tagline {
  margin: 0;
  font-size: 14px;
  line-height: var(--lh-relaxed);
}

.footer-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 6px 24px;
}

.footer-nav__link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 0;
  font-size: 14px;
  font-weight: 600;
  text-decoration: none;
  color: var(--color-primary-brown);
  position: relative;
}

.footer-nav__link::before {
  content: '›';
  font-size: 14px;
  color: rgba(90, 58, 18, 0.7);
}

.footer-nav__link:hover {
  color: var(--color-accent-orange);
}

.site-footer__bottom {
  border-top: 1px solid rgba(90, 58, 18, 0.15);
  margin-top: var(--space-8);
}

.site-footer__copy {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-8) var(--space-8);
  font-size: var(--fs-small);
  color: rgba(90, 58, 18, 0.8);
}

/* Responsive behaviour */
@media (max-width: 960px) {
  .site-header__inner {
    padding-inline: var(--space-4);
  }

  .main-nav__list {
    gap: 4px;
  }

  .main-nav__link {
    padding-inline: 10px;
    font-size: 13px;
  }
}

@media (max-width: 800px) {
  .site-header__inner {
    align-items: center;
  }

  .main-nav {
    position: absolute;
    inset-inline: 0;
    top: 100%;
    padding: 0 var(--space-4) var(--space-8);
    transform-origin: top;
    transform: scaleY(0);
    opacity: 0;
    pointer-events: none;
    transition: transform 0.15s ease, opacity 0.15s ease;
  }

  .main-nav__list {
    flex-direction: column;
    align-items: stretch;
    padding: var(--space-4);
    border-radius: 0 0 var(--radius-card) var(--radius-card);
    background-color: rgba(255, 244, 216, 0.98);
    box-shadow: var(--shadow-soft);
  }

  .main-nav__link {
    justify-content: flex-start;
    width: 100%;
  }

  .nav-toggle__label {
    display: inline-flex;
  }

  .nav-toggle:checked + .nav-toggle__label + .main-nav {
    transform: scaleY(1);
    opacity: 1;
    pointer-events: auto;
  }

  .site-main {
    padding-top: var(--space-12);
  }

  .site-footer__inner {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 480px) {
  .brand__name {
    font-size: 18px;
  }

  .brand__icon {
    width: 38px;
    height: 38px;
    font-size: 22px;
  }

  .site-main {
    padding-inline: var(--space-4);
  }
}
